import{_ as e,o as a,c as r,a2 as i}from"./chunks/framework.C58al07P.js";const u=JSON.parse('{"title":"User Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/index.md","filePath":"en/guide/index.md"}'),o={name:"en/guide/index.md"};function n(s,t,d,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="user-guide" tabindex="-1">User Guide <a class="header-anchor" href="#user-guide" aria-label="Permalink to &quot;User Guide&quot;">​</a></h1><p>Welcome to the Nid user guide. This section explains how to use each feature of the application.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Nid is a Gmail mailbox management and archiving application, installed on your own hardware (NAS, server). Your emails stay on your network — no data is sent to third-party servers.</p><h3 id="what-you-can-do" tabindex="-1">What you can do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What you can do&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./dashboard.html"><strong>Dashboard</strong></a></td><td>View your mailbox statistics at a glance</td></tr><tr><td><a href="./mail-management.html"><strong>Mail management</strong></a></td><td>Delete, label and archive in bulk</td></tr><tr><td><a href="./archiving.html"><strong>Archiving</strong></a></td><td>Back up your emails to your NAS in EML format</td></tr><tr><td><a href="./rules.html"><strong>Automatic rules</strong></a></td><td>Create rules to automate cleanup</td></tr><tr><td><a href="./newsletters.html"><strong>Newsletters</strong></a></td><td>Identify and clean up newsletters in one click</td></tr><tr><td><a href="./attachments.html"><strong>Attachments</strong></a></td><td>Manage and download your attachments</td></tr><tr><td><a href="./duplicates.html"><strong>Duplicates</strong></a></td><td>Detect and delete duplicate emails</td></tr><tr><td><a href="./analytics.html"><strong>Analytics</strong></a></td><td>Analyze your email habits with charts</td></tr><tr><td><a href="./privacy.html"><strong>Privacy</strong></a></td><td>Detect tracking pixels and protect your data</td></tr><tr><td><a href="./unified-inbox.html"><strong>Unified inbox</strong></a></td><td>View all your Gmail accounts in a single view</td></tr><tr><td><a href="./saved-searches.html"><strong>Saved searches</strong></a></td><td>Save your favorite filters</td></tr><tr><td><a href="./ops-resilience.html"><strong>Ops &amp; Resilience</strong></a></td><td>S3 storage, retention, API quota, import/export</td></tr><tr><td><a href="./notifications.html"><strong>Notifications</strong></a></td><td>Stay informed via in-app notifications and webhooks</td></tr><tr><td><a href="./settings.html"><strong>Settings</strong></a></td><td>2FA, export/import, language, theme</td></tr><tr><td><a href="./admin.html"><strong>Administration</strong></a></td><td>Manage users and quotas (admins)</td></tr></tbody></table><hr><h2 id="navigating-the-application" tabindex="-1">Navigating the application <a class="header-anchor" href="#navigating-the-application" aria-label="Permalink to &quot;Navigating the application&quot;">​</a></h2><p>The interface consists of:</p><ul><li>A <strong>sidebar</strong> on the left with links to each section</li><li>A <strong>Gmail account selector</strong> at the top of the sidebar to choose the active account</li><li>A <strong>navigation bar</strong> at the top with the notification bell, language selector, and dark/light theme toggle</li></ul><blockquote><p>📸 <em>Suggested screenshot: overview of the interface with the sidebar, header and account selector highlighted</em></p></blockquote><hr><h2 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h2><p>If you have just installed Nid, start with the <a href="./first-steps.html"><strong>First steps</strong></a> guide which walks you through:</p><ol><li>Creating your account</li><li>Connecting your first Gmail account</li><li>Exploring the dashboard</li><li>Your first cleanup operation</li></ol>',16)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
